    "example_question_sqls": [
      {
        "id": "01eeb472ffbb117eb7790af858ccc5b9",
        "question": [
          "give me in each instrument type the most with the high leverage  from the last 2 weeks"
        ],
        "sql": [
          "SELECT di.InstrumentType, MAX(dp.Leverage) as MaxLeverage \r\n",
          "--allways add prefixes like di or dp in the selected cilumns!\r\n",
          "FROM main.data_rooms.vw_dim_instrument di \r\n",
          "JOIN main.dwh.dim_position dp \r\n",
          "ON di.InstrumentID = dp.InstrumentID WHERE dp.OpenOccurred >= date_sub(current_date(), 14) \r\n",
          "GROUP BY di.InstrumentType"
        ]
      },
      {
        "id": "01ef347dfdcc1f83a32c67b767354ab6",
        "question": [
          "how many instruments with  tradable ,  visable, and not visible internal only"
        ],
        "sql": [
          "SELECT\n",
          "  COUNT(*) AS Total,\n",
          "  COUNT(\n",
          "    CASE\n",
          "      WHEN VisibleInternallyOnly = 0 and  Tradable = 1\n",
          "  AND InstrumentVisible = 1 THEN 1\n",
          "    END\n",
          "  ) AS TotalTradableVisibleExternally\n",
          "FROM\n",
          "  main.data_rooms.vw_dim_instrument"
        ]
      },
      {
        "id": "01efe6de72c512699214925dde93e881",
        "question": [
          "what are etoro regions ?"
        ],
        "sql": [
          "SELECT DISTINCT\n",
          "  `Region`\n",
          "FROM\n",
          "  `main`.`data_rooms`.`vw_cidfirstdates`"
        ]
      },
      {
        "id": "01efe6dee6de1f11ad63dfe59141b2f2",
        "question": [
          "keep here the top 12 and define them as main regions"
        ],
        "sql": [
          "WITH filtered_data AS (\n",
          "  SELECT\n",
          "    `Region`,\n",
          "    `CID`,\n",
          "    `registered`,\n",
          "    `FirstDepositDate`\n",
          "  FROM\n",
          "    `main`.`data_rooms`.`vw_cidfirstdates`\n",
          "  WHERE\n",
          "    `registered` >= '2024-01-01'\n",
          "    AND `registered` < '2025-01-01'\n",
          "),\n",
          "ranked_regions AS (\n",
          "  SELECT\n",
          "    `Region`,\n",
          "    COUNT(`CID`) AS `TotalRegisteredUsers`,\n",
          "    COUNT(`FirstDepositDate`) AS `TotalFTDs`,\n",
          "    ROW_NUMBER() OVER (ORDER BY COUNT(`FirstDepositDate`) DESC, COUNT(`CID`) DESC) AS `Rank`\n",
          "  FROM\n",
          "    filtered_data\n",
          "  GROUP BY\n",
          "    `Region`\n",
          ")\n",
          "SELECT\n",
          "  `Region`,\n",
          "  `TotalRegisteredUsers`,\n",
          "  `TotalFTDs`\n",
          "FROM\n",
          "  ranked_regions\n",
          "WHERE\n",
          "  `Rank` <= 12"
        ]
      },
      {
        "id": "01efe6e05e7e1334b1ee919e09435fe7",
        "question": [
          "defintion of ftds should be the sum of total new ftds in 2024 per main region"
        ],
        "sql": [
          "WITH filtered_data AS (\n",
          "  SELECT\n",
          "    cfd.`Region`,\n",
          "    pos.`Commission`,\n",
          "    cfd.`FirstDepositDate`,\n",
          "    cfd.`CID`\n",
          "  FROM\n",
          "    `main`.`data_rooms`.`vw_cidfirstdates` cfd\n",
          "      JOIN `main`.`data_rooms`.`vw_dim_position` pos ON cfd.`CID` = pos.`CID`\n",
          "  WHERE\n",
          "    pos.`OpenOccurred` >= '2024-01-01'\n",
          "    AND pos.`OpenOccurred` < '2025-01-01'\n",
          "    AND cfd.`Region` IN (\n",
          "      SELECT\n",
          "        `Region`\n",
          "      FROM\n",
          "        (\n",
          "          WITH filtered_data AS (\n",
          "            SELECT\n",
          "              `Region`,\n",
          "              `CID`,\n",
          "              `registered`,\n",
          "              `FirstDepositDate`\n",
          "            FROM\n",
          "              `main`.`data_rooms`.`vw_cidfirstdates`\n",
          "            WHERE\n",
          "              `registered` >= '2024-01-01'\n",
          "              AND `registered` < '2025-01-01'\n",
          "          ),\n",
          "          ranked_regions AS (\n",
          "            SELECT\n",
          "              `Region`,\n",
          "              COUNT(`CID`) AS `TotalRegisteredUsers`,\n",
          "              COUNT(`FirstDepositDate`) AS `TotalFTDs`,\n",
          "              ROW_NUMBER() OVER (\n",
          "                  ORDER BY COUNT(`FirstDepositDate`) DESC, COUNT(`CID`) DESC\n",
          "                ) AS `Rank`\n",
          "            FROM\n",
          "              filtered_data\n",
          "            GROUP BY\n",
          "              `Region`\n",
          "          )\n",
          "          SELECT\n",
          "            `Region`\n",
          "          FROM\n",
          "            ranked_regions\n",
          "          WHERE\n",
          "            `Rank` <= 12\n",
          "        )\n",
          "    )\n",
          ")\n",
          "SELECT\n",
          "  `Region`,\n",
          "  SUM(`Commission`) AS `TotalCommission`,\n",
          "  COUNT(DISTINCT CASE\n",
          "      WHEN `FirstDepositDate` >= '2024-01-01' AND `FirstDepositDate` < '2025-01-01' THEN `CID`\n",
          "    END) AS `TotalFTDs`\n",
          "FROM\n",
          "  filtered_data\n",
          "GROUP BY\n",
          "  `Region`\n",
          "WITH ROLLUP\n",
          "ORDER BY\n",
          "  `Region`"
        ]
      },
      {
        "id": "01f0291c06b71303b32794ffbd9bb858",
        "question": [
          "what are the top 5 instrument name that has the biggest amount in the last week?"
        ],
        "sql": [
          "SELECT\n",
          "  `vw_dim_instrument`.`InstrumentDisplayName`,\n",
          "  SUM(`vw_dim_position`.`Amount`) AS `TotalAmount`\n",
          "FROM\n",
          "  `main`.`data_rooms`.`vw_dim_position`\n",
          "    JOIN `main`.`data_rooms`.`vw_dim_instrument`\n",
          "      ON `vw_dim_position`.`InstrumentID` = `vw_dim_instrument`.`InstrumentID`\n",
          "WHERE\n",
          "  `vw_dim_position`.`OpenOccurred` >= date_sub(current_date(), 7)\n",
          "GROUP BY\n",
          "  `vw_dim_instrument`.`InstrumentDisplayName`\n",
          "ORDER BY\n",
          "  `TotalAmount` DESC\n",
          "LIMIT 5"
        ]
      }
    ],
