        "id": "01f0dfe3bf58189e903a27deede15c0b",
        "question": [
          "Number of German Crypto Holders who have active Tangany accounts."
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "SELECT COUNT(DISTINCT cfd.TanganyID) AS num_tangany_accounts\n",
              "FROM main.data_rooms.vw_cidfirstdates cfd\n",
              "JOIN main.data_rooms.vw_dim_position pos ON cfd.CID = pos.CID\n",
              "JOIN main.data_rooms.vw_dim_instrument ins ON pos.InstrumentID = ins.InstrumentID\n",
              "WHERE cfd.Country ILIKE '%germany%'\n",
              "  AND cfd.TanganyID IS NOT NULL\n",
              "  AND ins.InstrumentType ILIKE '%crypto currencies%'\n",
              "  AND pos.CloseDateID = 0"
            ]
          }
        ]
      },
